package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Method;
import java.util.ArrayList;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class JsonArrayTest {

  private JsonArray jsonArrayMock;
  private JsonElement jsonElementMock;

  @BeforeEach
  void setUp() {
    jsonArrayMock = Mockito.spy(new JsonArray());
    jsonElementMock = mock(JsonElement.class);
  }

  @Test
  void getAsFloat_singleElement_returnsFloat() throws Exception {
    // Arrange
    Method getAsSingleElementMethod = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    getAsSingleElementMethod.setAccessible(true);

    doReturn(jsonElementMock).when(jsonArrayMock).getAsFloat(); // stub getAsFloat on jsonElementMock below

    // Instead of mocking getAsSingleElement directly (private), mock getAsFloat on the returned element
    // So we mock getAsSingleElement via reflection to return jsonElementMock

    // To mock the private method getAsSingleElement, we use doAnswer:
    doAnswer(invocation -> jsonElementMock).when(jsonArrayMock, "getAsSingleElement");

    when(jsonElementMock.getAsFloat()).thenReturn(3.14f);

    // Act
    float result = jsonArrayMock.getAsFloat();

    // Assert
    assertEquals(3.14f, result, 0.0001f);
    verify(jsonElementMock).getAsFloat();
  }

  @Test
  void getAsSingleElement_privateMethod_returnsFirstElement() throws Exception {
    // Arrange
    JsonArray jsonArray = new JsonArray();
    JsonElement first = mock(JsonElement.class);
    JsonElement second = mock(JsonElement.class);
    jsonArray.add(first);
    jsonArray.add(second);

    // Use reflection to invoke private method getAsSingleElement
    Method method = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    method.setAccessible(true);

    // Act
    JsonElement result = (JsonElement) method.invoke(jsonArray);

    // Assert
    assertSame(first, result);
  }

  @Test
  void getAsSingleElement_privateMethod_emptyList_throwsException() throws Exception {
    JsonArray jsonArray = new JsonArray();

    Method method = JsonArray.class.getDeclaredMethod("getAsSingleElement");
    method.setAccessible(true);

    assertThrows(IndexOutOfBoundsException.class, () -> {
      method.invoke(jsonArray);
    });
  }

  @Test
  void getAsFloat_withRealJsonArray_returnsFloat() {
    JsonArray jsonArray = new JsonArray();
    JsonPrimitive jsonPrimitive = new JsonPrimitive(5.5f);
    jsonArray.add(jsonPrimitive);

    float result = jsonArray.getAsFloat();

    assertEquals(5.5f, result, 0.0001f);
  }
}
```

---

**Note:** Since Mockito cannot mock private methods directly, the original calls to `doReturn(jsonElementMock).when(jsonArrayMock).getAsSingleElement()` and `verify(jsonArrayMock).getAsSingleElement()` cause compile errors.

To fix this:

- Removed direct mocking/verification of the private method `getAsSingleElement`.
- Instead, used `doAnswer` with the method name string to mock the private method call.
- Verified interactions on the returned mock `jsonElementMock` only.

If your Mockito version does not support `doAnswer(invocation -> ...)` with method name string (this is a Mockito-inline or advanced feature), you can alternatively use reflection to replace the private method or test via public API only.

If you want a simpler approach without mocking the private method, just mock the returned element's `getAsFloat()` and call the public method.
